local amplitude = 0.3000
local location_amplitude = 4.9700
local fov_amplitude = 0.0444
local frequency = 15.0000
local duration = 3.7000
-- Rotation Bezier
local cp1x = 0.0000
local cp1y = 0.0000
local cp2x = 0.9922
local cp2y = 0.0000
local cp0y = 0.0000
local cp3y = 0.0000
-- Location Bezier
local loc_cp1x = 0.0469
local loc_cp1y = 0.0000
local loc_cp2x = 1.0000
local loc_cp2y = 0.0000
local loc_cp0y = 0.0000
local loc_cp3y = 0.0000
-- FOV Bezier
